from pymongo import MongoClient

def execute_custom_query(database_name, collection_name, query_expression):
    client = MongoClient('mongodb://localhost:27017/')
    db = client[database_name]
    collection = db[collection_name]

    # Construct the query using $where with the user-provided expression
    custom_query = {
        "$where": f"function() {{ return {query_expression}; }}"
    }

    results = collection.find(custom_query)

    for document in results:
        print(document)

    client.close()

